const q = $input.first().json.query || {};
const { t, p, r } = q;
if (!t || !p || !r) throw new Error('Missing required query params: t, p, r');
if (r !== 'good' && r !== 'bad') throw new Error(`Invalid rating value: ${r}`);
let client_slug, source_type, source_ref;
try {
  const decoded = Buffer.from(p, 'base64url').toString('utf8');
  const parts = decoded.split(':');
  if (parts.length < 3) throw new Error('Unexpected payload format');
  [client_slug, source_type, source_ref] = parts;
} catch (e) {
  throw new Error(`Failed to decode token payload: ${e.message}`);
}
return [{ json: { t, p, r, client_slug, source_type, source_ref } }];

const token_data = $('Parse and Decode Params').first().json;
const config = $input.first().json;
return [{ json: {
  ...token_data,
  ...config,
  action: 'verify',
  token: token_data.t,
  payload_b64: token_data.p,
  secret: config.link_signing_secret
} }];

const config = $input.first().json;
const enabled = Array.isArray(config.enabled_features) && config.enabled_features.includes('reviews');
return [{ json: { ...config, enabled } }];

const d = $('Merge Token Data and Config').first().json;
const isNew = d.lead_sheet_tab === 'Leads';
return [{ json: {
  source_type:    d.source_type,
  source_ref:     d.source_ref,
  lead_sheet_id:  d.lead_sheet_id,
  lead_sheet_tab: d.lead_sheet_tab,
  fields: isNew ? { 'Rating': d.r } : { 'Rating Received': d.r }
} }];

const d = $('Merge Token Data and Config').first().json;
const isNew = d.lead_sheet_tab === 'Leads';
return [{ json: {
  source_type:    d.source_type,
  source_ref:     d.source_ref,
  lead_sheet_id:  d.lead_sheet_id,
  lead_sheet_tab: d.lead_sheet_tab,
  fields: isNew ? {} : { 'Needs Followup': 'TRUE' }
} }];

const d = $('Merge Token Data and Config').first().json;
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const html = `<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#333;">
  <h2 style="color:#e74c3c;">A customer reported a poor experience</h2>
  <p>Hi ${d.client_name} team,</p>
  <p>A customer clicked "Could Be Better" in their review request email on ${today}.</p>
  <table style="border-collapse:collapse;width:100%;margin:20px 0;">
    <tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Business</td><td style="padding:8px;border:1px solid #ddd;">${d.client_name}</td></tr>
    <tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Lead Row #</td><td style="padding:8px;border:1px solid #ddd;">${d.source_ref}</td></tr>
  </table>
  <p>Please look up row <strong>${d.source_ref}</strong> in the ${d.client_name} Leads sheet to identify the customer and follow up personally.</p>
  <hr style="border:none;border-top:1px solid #eee;margin:20px 0;">
  <p style="font-size:12px;color:#999;">This message was sent by CAIAC Digital's AI.</p>
</body>
</html>`;
return [{ json: {
  to: d.review_notify_email,
  from: 'no_reply@caiacdigital.com',
  subject: `Customer Feedback Follow-up Required — ${d.client_name}`,
  html
} }];
